class PerformanceOptimizer{constructor(){this.lazyImages=[];this.intersectionObserver=null;this.loadingIndicators=new Map();this.init();}init(){this.initLazyLoading();this.initProgressiveLoading();this.optimizeScrollPerformance();this.optimizeBundleLoading();this.monitorPerformance();}initLazyLoading(){if('IntersectionObserver'in window){this.intersectionObserver=new IntersectionObserver(this.handleIntersection.bind(this),{rootMargin:'50px 0px',threshold:0.01});this.setupLazyElements();}else{this.loadAllImages();}}setupLazyElements(){const lazyImages=document.querySelectorAll('img[data-src]');lazyImages.forEach(img=>{this.lazyImages.push(img);this.intersectionObserver.observe(img);});const lazyContent=document.querySelectorAll('[data-lazy-content]');lazyContent.forEach(element=>{this.intersectionObserver.observe(element);});const lazyBackgrounds=document.querySelectorAll('[data-bg-src]');lazyBackgrounds.forEach(element=>{this.intersectionObserver.observe(element);});}handleIntersection(entries){entries.forEach(entry=>{if(entry.isIntersecting){const element=entry.target;if(element.tagName==='IMG'&&element.dataset.src){this.loadImage(element);}else if(element.dataset.lazyContent){this.loadContent(element);}else if(element.dataset.bgSrc){this.loadBackgroundImage(element);}this.intersectionObserver.unobserve(element);}});}loadImage(img){const imageLoader=new Image();imageLoader.onload=()=>{img.src=img.dataset.src;img.classList.add('loaded');img.removeAttribute('data-src');};imageLoader.onerror=()=>{img.classList.add('error');img.src='/static/images/placeholder.png';};imageLoader.src=img.dataset.src;}loadBackgroundImage(element){const imageLoader=new Image();imageLoader.onload=()=>{element.style.backgroundImage=`url(${element.dataset.bgSrc})`;element.classList.add('bg-loaded');element.removeAttribute('data-bg-src');};imageLoader.src=element.dataset.bgSrc;}loadContent(element){const contentUrl=element.dataset.lazyContent;if(contentUrl){this.showLoadingIndicator(element);fetch(contentUrl).then(response=>response.text()).then(html=>{element.innerHTML=html;element.classList.add('content-loaded');element.removeAttribute('data-lazy-content');}).catch(error=>{console.error('Failed to load lazy content:',error);element.innerHTML='<p>Failed to load content</p>';}).finally(()=>{this.hideLoadingIndicator(element);});}}loadAllImages(){const lazyImages=document.querySelectorAll('img[data-src]');lazyImages.forEach(img=>{img.src=img.dataset.src;img.removeAttribute('data-src');});}initProgressiveLoading(){this.connectionSpeed=this.getConnectionSpeed();if(this.connectionSpeed==='slow'){this.enableProgressiveMode();}if('connection'in navigator){navigator.connection.addEventListener('change',()=>{this.connectionSpeed=this.getConnectionSpeed();this.adjustForConnection();});}}getConnectionSpeed(){if('connection'in navigator){const connection=navigator.connection;if(connection.effectiveType==='slow-2g'||connection.effectiveType==='2g'){return'slow';}else if(connection.effectiveType==='3g'){return'medium';}else{return'fast';}}return'unknown';}enableProgressiveMode(){document.body.classList.add('progressive-mode');const images=document.querySelectorAll('img[data-src]');images.forEach(img=>{if(img.dataset.srcLow){img.dataset.src=img.dataset.srcLow;}});this.deferNonCriticalResources();}adjustForConnection(){if(this.connectionSpeed==='slow'){this.enableProgressiveMode();}else{document.body.classList.remove('progressive-mode');}}deferNonCriticalResources(){const nonCriticalCSS=document.querySelectorAll('link[data-defer]');nonCriticalCSS.forEach(link=>{setTimeout(()=>{link.rel='stylesheet';},1000);});const nonCriticalJS=document.querySelectorAll('script[data-defer]');nonCriticalJS.forEach(script=>{setTimeout(()=>{const newScript=document.createElement('script');newScript.src=script.dataset.src;newScript.async=true;document.head.appendChild(newScript);},2000);});}optimizeScrollPerformance(){let ticking=false;const optimizedScrollHandler=()=>{if(!ticking){requestAnimationFrame(()=>{this.handleScroll();ticking=false;});ticking=true;}};window.addEventListener('scroll',optimizedScrollHandler,{passive:true});let resizeTimeout;window.addEventListener('resize',()=>{clearTimeout(resizeTimeout);resizeTimeout=setTimeout(()=>{this.handleResize();},250);},{passive:true});}handleScroll(){const scrollTop=window.pageYOffset||document.documentElement.scrollTop;this.updateScrollBasedElements(scrollTop);this.checkForMoreContent(scrollTop);}updateScrollBasedElements(scrollTop){const header=document.querySelector('.header');if(header){if(scrollTop>this.lastScrollTop&&scrollTop>100){header.classList.add('header-hidden');}else{header.classList.remove('header-hidden');}this.lastScrollTop=scrollTop;}}checkForMoreContent(scrollTop){const windowHeight=window.innerHeight;const documentHeight=document.documentElement.scrollHeight;if(scrollTop+windowHeight>documentHeight-1000){this.loadMoreContent();}}loadMoreContent(){const loadMoreButton=document.querySelector('[data-load-more]');if(loadMoreButton&&!loadMoreButton.disabled){loadMoreButton.click();}}handleResize(){this.setupLazyElements();this.updateResponsiveImages();}updateResponsiveImages(){const responsiveImages=document.querySelectorAll('img[data-sizes]');responsiveImages.forEach(img=>{const sizes=JSON.parse(img.dataset.sizes);const windowWidth=window.innerWidth;let bestSize=sizes[0];for(const size of sizes){if(windowWidth>=size.minWidth){bestSize=size;}}if(img.src!==bestSize.src){img.src=bestSize.src;}});}optimizeBundleLoading(){this.preloadCriticalResources();this.loadNonCriticalBundles();this.setupModuleLoading();}preloadCriticalResources(){const criticalResources=['/static/css/main.css','/static/js/main.js'];criticalResources.forEach(resource=>{const link=document.createElement('link');link.rel='preload';link.as=resource.endsWith('.css')?'style':'script';link.href=resource;document.head.appendChild(link);});}loadNonCriticalBundles(){window.addEventListener('load',()=>{setTimeout(()=>{this.loadModule('notifications');this.loadModule('analytics');},1000);});}loadModule(moduleName){if(!window.loadedModules){window.loadedModules=new Set();}if(window.loadedModules.has(moduleName)){return Promise.resolve();}return new Promise((resolve,reject)=>{const script=document.createElement('script');script.src=`/static/js/${moduleName}.js`;script.async=true;script.onload=()=>{window.loadedModules.add(moduleName);resolve();};script.onerror=reject;document.head.appendChild(script);});}setupModuleLoading(){document.addEventListener('click',(e)=>{const target=e.target.closest('[data-module]');if(target){const moduleName=target.dataset.module;this.loadModule(moduleName);}});}showLoadingIndicator(element){const indicator=document.createElement('div');indicator.className='loading-indicator';indicator.innerHTML=`<div class="loading-spinner"></div><p>Loading...</p>`;element.appendChild(indicator);this.loadingIndicators.set(element,indicator);}hideLoadingIndicator(element){const indicator=this.loadingIndicators.get(element);if(indicator){indicator.remove();this.loadingIndicators.delete(element);}}monitorPerformance(){if('PerformanceObserver'in window){this.monitorLCP();this.monitorFID();this.monitorCLS();}this.monitorCustomMetrics();}monitorLCP(){const observer=new PerformanceObserver((list)=>{const entries=list.getEntries();const lastEntry=entries[entries.length-1];console.log('LCP:',lastEntry.startTime);this.reportMetric('lcp',lastEntry.startTime);});observer.observe({entryTypes:['largest-contentful-paint']});}monitorFID(){const observer=new PerformanceObserver((list)=>{const entries=list.getEntries();entries.forEach(entry=>{console.log('FID:',entry.processingStart-entry.startTime);this.reportMetric('fid',entry.processingStart-entry.startTime);});});observer.observe({entryTypes:['first-input']});}monitorCLS(){let clsValue=0;const observer=new PerformanceObserver((list)=>{const entries=list.getEntries();entries.forEach(entry=>{if(!entry.hadRecentInput){clsValue+=entry.value;}});console.log('CLS:',clsValue);this.reportMetric('cls',clsValue);});observer.observe({entryTypes:['layout-shift']});}monitorCustomMetrics(){window.addEventListener('load',()=>{setTimeout(()=>{const tti=performance.now();console.log('TTI:',tti);this.reportMetric('tti',tti);},0);});window.addEventListener('load',()=>{const resources=performance.getEntriesByType('resource');resources.forEach(resource=>{if(resource.duration>1000){console.log('Slow resource:',resource.name,resource.duration);}});});}reportMetric(name,value){if(window.gtag){window.gtag('event','web_vitals',{event_category:'Performance',event_label:name,value:Math.round(value)});}}}document.addEventListener('DOMContentLoaded',()=>{window.performanceOptimizer=new PerformanceOptimizer();});const style=document.createElement('style');style.textContent=`img[data-src]{opacity:0;transition:opacity 0.3s;}img.loaded{opacity:1;}img.error{opacity:0.5;filter:grayscale(100%);}.loading-indicator{display:flex;flex-direction:column;align-items:center;justify-content:center;padding:2rem;color:#6b7280;}.loading-spinner{width:32px;height:32px;border:3px solid#e5e7eb;border-top:3px solid#6366f1;border-radius:50%;animation:spin 1s linear infinite;margin-bottom:1rem;}@keyframes spin{0%{transform:rotate(0deg);}100%{transform:rotate(360deg);}}.progressive-mode img{image-rendering:auto;image-rendering:crisp-edges;image-rendering:pixelated;}.progressive-mode.non-critical{display:none;}.header{transition:transform 0.3s ease;}.header-hidden{transform:translateY(-100%);}@media(prefers-reduced-motion:reduce){*{animation-duration:0.01ms!important;animation-iteration-count:1!important;transition-duration:0.01ms!important;}}@media(prefers-contrast:high){.loading-spinner{border-color:currentColor;border-top-color:transparent;}}`;document.head.appendChild(style);